import { Container, Nav, Navbar, Dropdown } from "react-bootstrap";
import { Link, useLocation, useNavigate } from "react-router-dom";

function AppNavbar({ user, setUser }) {
  const navigate = useNavigate();
  const location = useLocation();

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    if (setUser) setUser(null);
    navigate("/login");
  };

  const getInitial = () => {
    if (!user?.full_name) return "U";
    return user.full_name.trim().charAt(0).toUpperCase();
  };

  return (
    <Navbar expand="lg" className="user-navbar" variant="dark">
      <Container fluid="xl">
        <Navbar.Brand as={Link} to={user ? "/home" : "/"}>
          Concert Ticket
        </Navbar.Brand>

        <Navbar.Toggle aria-controls="main-user-navbar" />

        <Navbar.Collapse id="main-user-navbar">
          <Nav className="mx-auto align-items-center">
            <Nav.Link
              as={Link}
              to={user ? "/home" : "/"}
              className={
                location.pathname === "/home" || location.pathname === "/"
                  ? "active"
                  : ""
              }
            >
              Trang chủ
            </Nav.Link>

            <Nav.Link
              as={Link}
              to="/home"
              className={location.pathname.startsWith("/event") ? "active" : ""}
            >
              Sự kiện
            </Nav.Link>

            {user && (
              <Nav.Link
                as={Link}
                to="/profile"
                className={location.pathname === "/profile" ? "active" : ""}
              >
                Hồ sơ
              </Nav.Link>
            )}
          </Nav>

          <div className="d-flex align-items-center">
            {user ? (
              <Dropdown align="end">
                <Dropdown.Toggle
                  variant="link"
                  className="d-flex align-items-center text-decoration-none border-0 p-0 shadow-none"
                >
                  <span className="navbar-avatar me-2">{getInitial()}</span>
                </Dropdown.Toggle>

                <Dropdown.Menu className="border-0 shadow rounded-4 p-2">
                  <Dropdown.Header className="fw-bold">
                    {user.full_name || "Người dùng"}
                  </Dropdown.Header>

                  <Dropdown.Item as={Link} to="/profile" className="rounded-3">
                    Hồ sơ của tôi
                  </Dropdown.Item>

                  <Dropdown.Item as={Link} to="/home" className="rounded-3">
                    Danh sách sự kiện
                  </Dropdown.Item>

                  {user.role === "admin" && (
                    <Dropdown.Item as={Link} to="/admin" className="rounded-3">
                      Vào trang quản trị
                    </Dropdown.Item>
                  )}

                  <Dropdown.Divider />

                  <Dropdown.Item
                    onClick={handleLogout}
                    className="rounded-3 text-danger fw-semibold"
                  >
                    Đăng xuất
                  </Dropdown.Item>
                </Dropdown.Menu>
              </Dropdown>
            ) : (
              <div className="d-flex gap-2">
                <Link to="/login" className="btn soft-button soft-button-outline">
                  Đăng nhập
                </Link>
                <Link
                  to="/register"
                  className="btn soft-button soft-button-primary"
                >
                  Đăng ký
                </Link>
              </div>
            )}
          </div>
        </Navbar.Collapse>
      </Container>
    </Navbar>
  );
}

export default AppNavbar;
